refsection.programlisting:

load(GROCERDIR+'/data/bdhenderic.dat') ;
bounds('1964q3','1988q4');
rarma=varma('rnet',[0 0],[],[0],[],0,1,'exo=''const''','Gexo=1')
// estimation of an ARMA(2,1) on the interest data in the database bdhenderic.dat provided with grocer
rarmf=varmaf(rarma,10,'exo=''const''')
// makes a forecast on the first 10 out-of-sample observations
rarmf=varmaf(rarma,'1991q2','exo=''const''')
// makes a forecast from the first out-of-sample date (here '1989q1') to '1991q2': this is exactly the same as the first example
rarmf=varmaf(rarma,['1988q3' '1990q4'],'exo=''const''')
// makes a forecast from an in-sample date ('1988q3') to an out-of-sample date ('1990q4')
rarmf=varmaf(rarma,['1989q3' '1990q4'],'exo=''const''')
// makes a forecast from a date three quarters after the end of estimation period to an out-of-sample date;
// note that it is possible since data on rnet are available until 1989q4,
// that is after the start of the forecast.
